  # Build a flat list of clause fragments for all subjects
      clause_fragments = []
      for subj, triple_list in subject_map.items():
          # Aggregate objects for each predicate of the same subject
          pred_objects = {}
          for t in triple_list:
              pred_objects.setdefault(t.predicate, []).append(t.object)

          for pred, objs in pred_objects.items():
              tmpl = templates.get(pred)
              if tmpl:
                  # Create a fragment for each object to keep grammar correct
                  for obj in objs:
                      clause_fragments.append(tmpl(subj, obj))
              else:
                  # Fallback for unknown predicates
                  obj_str = " and ".join(objs)
                  clause_fragments.append(f"{subj} {pred} {obj_str}")

      if not clause_fragments:
          return ""

      # Join all fragments into a single fluent sentence
      if len(clause_fragments) == 1:
          sentence = clause_fragments[0] + "."
      else:
          sentence = ", ".join(clause_fragments[:-1]) + ", and " + clause_fragments[-1] + "."
      return sentence
